(()=>{var t=document.querySelector("[data-jt-mark-all-read]");t&&window.jetonomyData&&t.addEventListener("click",function(e){e.preventDefault(),t.disabled=!0,fetch(window.jetonomyData.restBase+"/notifications/mark-all-read",{method:"POST",credentials:"same-origin",headers:{"X-WP-Nonce":window.jetonomyData.restNonce,"Content-Type":"application/json"}}).then(function(e){if(!e.ok)throw new Error("mark_all_read_failed");document.querySelectorAll(".jt-notif-dot").forEach(function(e){e.remove()}),t.remove()}).catch(function(){t.disabled=!1})})})();